// Budget monitoring and alert generation
const budgets = $input.first().json.result?.data || [];
const alerts = [];

for (const budget of budgets) {
  const percentage = budget.percentage || 0;
  const categoryName = budget.category?.name || 'Unknown';
  const spent = budget.spent || 0;
  const limit = budget.limit || 0;
  const remaining = limit - spent;

  // Generate alerts based on budget usage
  if (percentage >= 100) {
    // Over budget alert
    alerts.push({
      type: 'CRITICAL',
      title: `${categoryName} Budget Exceeded`,
      message: `You've exceeded your ${categoryName} budget by Birr ${Math.abs(remaining).toLocaleString()}. Consider reviewing your spending in this category.`,
      category: categoryName,
      budgetId: budget.id,
      percentage: percentage,
      priority: 'high',
      action: 'Review Budget'
    });
  } else if (percentage >= 90) {
    // Near limit warning
    alerts.push({
      type: 'WARNING',
      title: `${categoryName} Budget Alert`,
      message: `You've used ${percentage.toFixed(0)}% of your ${categoryName} budget. Only Birr ${remaining.toLocaleString()} remaining.`,
      category: categoryName,
      budgetId: budget.id,
      percentage: percentage,
      priority: 'medium',
      action: 'Monitor Spending'
    });
  } else if (percentage >= 75) {
    // Approaching limit info
    alerts.push({
      type: 'INFO',
      title: `${categoryName} Budget Update`,
      message: `You've used ${percentage.toFixed(0)}% of your ${categoryName} budget. You're doing well staying within limits.`,
      category: categoryName,
      budgetId: budget.id,
      percentage: percentage,
      priority: 'low',
      action: 'View Progress'
    });
  }
}

// Add summary alert if multiple budgets are over limit
const overBudgetCount = alerts.filter(a => a.type === 'CRITICAL').length;
if (overBudgetCount > 1) {
  alerts.push({
    type: 'CRITICAL',
    title: 'Multiple Budget Alerts',
    message: `You have ${overBudgetCount} categories over budget. Consider reviewing your overall spending strategy.`,
    category: 'Overall',
    budgetId: 'summary',
    percentage: 100,
    priority: 'high',
    action: 'Review All Budgets'
  });
}

return alerts.map(alert => ({ json: alert }));

// Send push notification for high priority alerts
const alert = $input.first().json;

return {
  notification: {
    title: alert.title,
    body: alert.message,
    icon: '/logo.png',
    badge: '/logo.png',
    tag: `budget-${alert.budgetId}`,
    requireInteraction: true,
    actions: [
      {
        action: 'view',
        title: 'View Budget'
      },
      {
        action: 'dismiss',
        title: 'Dismiss'
      }
    ]
  },
  webhook_url: 'http://localhost:3001/api/notifications/push',
  alert_data: alert
};
